------------------------------------------------------------------
--- delete string last section
--- "xx/yy/zz.o"    ->  "xx/yy", "zz.o"
--- "zz.o"          ->  "zz.o", nil
------------------------------------------------------------------
function LStringUtil.DelStringLastSection(path, key, init, plain)
	key = key or "/"
	init = init or 1
	plain = plain or true
	local sLastSection = nil
	local sBeginLeft = nil
	local str = tostring(path)
	local strReverse = string.reverse(str)
	local startpos,endpos = string.find(strReverse, key, init, plain)
	if (startpos) then
		endpos = string.len(strReverse) - endpos + 1
		sLastSection = string.sub(str, endpos + 1, -1)
		sBeginLeft = string.sub(str, 1, endpos - 1)
	else
		sLastSection = nil
		sBeginLeft = str
	end
	return sBeginLeft, sLastSection
end

------------------------------------------------------------------
--- get string last section
--- "xx/yy/zz.o"    ->  "zz.o", "xx/yy"
--- "zz.o"          ->  "zz.o", nil
------------------------------------------------------------------
function LStringUtil.GetStringLastSection(path, key, init, plain)
	key = key or "/"
	init = init or 1
	plain = plain or true
	local sLastSection = nil
	local sBeginLeft = nil
	local str = tostring(path)
	local strReverse = string.reverse(str)
	local startpos,endpos = string.find(strReverse, key, init, plain)
	if (startpos) then
		endpos = string.len(strReverse) - endpos + 1
		sLastSection = string.sub(str, endpos + 1, -1)
		sBeginLeft = string.sub(str, 1, endpos - 1)
	else
		sLastSection = str
		sBeginLeft = nil
	end
	return sLastSection or "", sBeginLeft
end
------------------------------------------------------------------
--- 字符串的处理
--- 字符串里的参数替换
--- param replace name = "${replacename}"
--- e.g. result = LUtil.ReplaceStringParam("我要打${some},${l}个", {"some","l"}, 10,20)
--- result = "我要打10个"
--- 如果paramNames = nil 那么会依次按照参数列表的个数替换 ${1},${2},${3} ..
--- e.g. result = LUtil.ReplaceStringParam("我要打${1}个,${2}个也行", nil, 10,11,12)
--- result = "我要打10个,11个也行"
------------------------------------------------------------------
function LStringUtil.ReplaceStringParam(str,paramNames,...)
	if not str then return end
	local params = {...}
	if #params == 0 then return str end
	local nameModel = "${%s}"
	local replstr
	if paramNames then
		for k,v in ipairs(params) do
			replstr = string.format(nameModel,tostring(paramNames[k]))
			str = string.gsub(str, replstr, tostring(v))
		end
	else
		for k,v in ipairs(params) do
			replstr = string.format(nameModel,tostring(k))
			str = string.gsub(str, replstr, tostring(v))
		end
	end
	return str
end

------------------------------------------------------------------
--- 字符串的处理
