------------------------------------------------------------------
--- 字符串匹配
--- sSrc = "xxxxk{ooo}yy"
--- sTitle = k
--- k{字母数字下划线}
--- return ooo
------------------------------------------------------------------
function LStringUtil.StringMatchFirst(strSrc, strTitle)
	local str = strSrc
	local sKeyword
	local posBegin,posEnd,subStr
	posBegin,posEnd,subStr = string.find(str, strTitle .. "{%s*[%w_]*%s*}")
	if (posBegin == nil) then
		return nil
	end
	sKeyword = string.sub(str, posBegin, posEnd)
	sKeyword = string.gsub(sKeyword, "[".. strTitle .. "|{|}|%s]", "")
	if (string.len(sKeyword) <= 0) then
		return nil
	end
	return sKeyword
end

------------------------------------------------------------------
--- 字符串匹配
--- sSrc = "xxxxk{ooo}yyk{bb}"
--- sTitle = k
--- k{字母数字下划线}
--- return {"ooo","bb"}
------------------------------------------------------------------
function LStringUtil.StringMatchAll(strSrc, strTitle)
	local retTab = {}
	local sKeyword
	local posBegin,posEnd,subStr
	local str = strSrc
	while true do
		posBegin,posEnd,subStr = string.find(str, strTitle .. "{%s*[%w_]*%s*}")
		if (posBegin == nil) then
			break
		end
		sKeyword = string.sub(str, posBegin, posEnd)
		sKeyword = string.gsub(sKeyword, "[".. strTitle .. "|{|}|%s]", "")
		table.insert(retTab, sKeyword)
		str = string.sub(str, posEnd, string.len(str))
	end
	return retTab
end

------------------------------------------------------------------
--- 字符串分割
--- strSrc = 123next456
--- strKey = next
--- tabPos = nil or retTab pos
--- tabMax = nil or retTab max count
--- return {123,456} or "" or retTab[tabPos]
------------------------------------------------------------------
function LStringUtil.StringSplit(strSrc, strKey, tabPos, tabMax)
	if (string.isempty(strSrc)) then
		return ""
	end
	local retTab = {}
	local sWord
	local posBegin,posEnd,subStr
	local str = strSrc
	local strPrev = ""
	while true do
		posBegin,posEnd,subStr = string.find(str, strKey)
		if (posBegin == nil) then
			table.insert(retTab, str)
			break
		end
		sWord = string.sub(str, 1, posBegin-1)
		table.insert(retTab, sWord)
		strPrev = str
		str = string.sub(str, posEnd+1, string.len(str))
		if (str == "" or strPrev == str) then
			break
		end
		if (tabMax and #retTab >= tabMax) then
			break
		end
	end
	if (not tabPos) then
		return retTab
	end
	if (tabPos > #retTab) then
		return ""
	end
	return retTab[tabPos]
end

