--- 字符串长度
--- 中文和英文都当成一个
------------------------------------------------------------------
function LStringUtil.StringLen(str)
	local tb = LStringUtil.StringToCharArray(str)
	return #tb
end
------------------------------------------------------------------
--- 字符串转成字符数组
--- UTF8的编码规则：
--- 1. 字符的第一个字节范围： 0x00—0x7F(0-127),或者 0xC2—0xF4(194-244) UTF8 是兼容 ascii 的，所以 0~127 就和 ascii 完全一致
--- 2. 0xC0, 0xC1,0xF5—0xFF(192, 193 和 245-255)不会出现在UTF8编码中
--- 3. 0x80—0xBF(128-191)只会出现在第二个及随后的编码中(针对多字节编码，如汉字)
------------------------------------------------------------------
function LStringUtil.StringToCharArray(s)
	local tb = {}
	for utfChar in string.gmatch(s, "[%z\1-\127\194-\244][\128-\191]*") do
		table.insert(tb, utfChar)
	end
	return tb
end

-----------------------------------------------------------------
---  1025 -> 1K 1Bytes
-----------------------------------------------------------------
function LStringUtil.FormatGMKB(byteSize)
	if (byteSize <= 0) then
		return " 0K "
	end
	local result = ""
	local g = math.floor(byteSize / 1073741824)
	local last = byteSize % 1073741824
	if (g > 0) then
		result = result .. g .. "G "
	end
	local m = math.floor(last / 1048576)
	last = last % 1048576
	if (m > 0) then
		result = result .. m .. "M "
	end
	local k = math.floor(last / 1024)
	last = last % 1024
	if (k > 0) then
		result = result .. k .. "K "
	end
	local b = last
	if (b > 0) then
		result = result .. b .. "Bytes "
	end
	return result
end
-----------------------------------------------------------------
--- 1025 -> 1.xM
-----------------------------------------------------------------
function LStringUtil.FormatDotGMK(byteSize)
	if (byteSize <= 0) then
		return " 0K "
	elseif (byteSize <= 1024) then
		return " 1K "
	end
	local result = ""
	local g = math.floor(byteSize / 1073741824)
	if (g > 0) then
		return string.format("%0.1fG", g)
	end
	local m = math.floor(byteSize / 1048576)
	if (m > 0) then
		return string.format("%0.1fM", m)
	end
	local k = math.floor(byteSize / 1024)
	if (k > 0) then
		return string.format("%0.1fK", k)
	end
	return result
end

