--- time format string
-----------------------------------------------------------------
--- timeFormat = "${yyyy}-${MM}-${dd} ${HH}:${mm}:${ss}"
-----------------------------------------------------------------
function LStringUtil.FormatTimestamp(timestamp, timeFormat)
	timeFormat = timeFormat or "${yyyy}-${MM}-${dd} ${HH}:${mm}:${ss}"
	local timeName = LStringUtil.StringMatchAll(timeFormat, "$")
	local date = LUtil.OSDate("*t", timestamp)
	local dateTab = {["y"]= date.year,["M"]= date.month,["d"]= date.day,["H"]= date.hour,["m"]= date.min,["s"]= date.sec}
	local dateVal = {}
	for k,v in pairs(timeName) do
		table.insert(dateVal, string.format("%0".. string.len(v) .. "d", dateTab[string.sub(v,1,1)]))
	end
	return LStringUtil.ReplaceStringParam(timeFormat, timeName, unpack(dateVal))
end


