--- 数字转汉字
-----------------------------------------------------------------
function LStringUtil.NumberToCN(num)
	if gLGameLanguage:IsForeignVersion() then
		return num
	end

	local hzUnit = {	
		ccClientText(2010), 
		ccClientText(2011), 
		ccClientText(2012), 
		ccClientText(2013)
	}
	local hzNum = {
		[0]	= ccClientText(2000),
		[1] = ccClientText(2001),
		[2] = ccClientText(2002),
		[3] = ccClientText(2003),
		[4] = ccClientText(2004),
		[5] = ccClientText(2005),
		[6] = ccClientText(2006),
		[7] = ccClientText(2007),
		[8] = ccClientText(2008),
		[9] = ccClientText(2009),
	}
	
	num = tonumber(num)
	if nil == num then
		return ''
	end

	len = string.len(num)
	if len == 1 then
		return hzNum[num]
	end

	if num == 10 then
		return hzUnit[1]
	end

	if num < 20 then
		return hzUnit[1]..hzNum[num%10]
	end

	if num < 100 and num % 10 == 0 then
		return hzNum[num/10]..hzUnit[1]
	end

	local weiNum = math.floor(num / (math.pow(10, len-1)) % 10)
	local afterNum = num % math.pow(10,len-1)
	local hzIndex = len - 1

	if string.len(afterNum)==1 and afterNum==0 then
		return hzNum[weiNum]..hzUnit[hzIndex]
	end

	if len - string.len(afterNum)>1 then
		return hzNum[weiNum]..hzUnit[hzIndex]..hzNum[0]..LStringUtil.NumberToCN(afterNum)
	end

	return hzNum[weiNum]..hzUnit[hzIndex]..LStringUtil.NumberToCN(afterNum)
end

